(function(w){"use strict";
function e(v){return String(v==null?"":v).replace(/[&<>"']/g,function(c){return {"&":"&amp;","<":"&lt;",">":"&gt;","\"":"&quot;","'":"&#39;"}[c]||c;});}
function renderField(f){var a=' data-key="'+e(f.key)+'"';if(f.raw)a+=' data-raw="1"';if(f.type==='select'){return '<div class="hm-calc-field"><label>'+e(f.label)+'</label><select class="hm-calc-select"'+a+'>'+f.options.map(function(o){return '<option value="'+e(o[0])+'"'+(String(o[0])===String(f.default)?' selected':'')+'>'+e(o[1])+'</option>';}).join('')+'</select></div>';}if(f.type==='textarea'){return '<div class="hm-calc-field"><label>'+e(f.label)+'</label><textarea class="hm-calc-input" rows="4"'+a+' placeholder="'+e(f.placeholder||'')+'">'+e(f.default||'')+'</textarea></div>';}var type=f.type==='date'?'date':'text';var mode=f.type==='integer'?'numeric':'decimal';return '<div class="hm-calc-field"><label>'+e(f.label)+'</label><input class="hm-calc-input" type="'+type+'" inputmode="'+mode+'"'+a+' placeholder="'+e(f.placeholder||'')+'" value="'+e(f.default||'')+'"></div>';}
function makeRender(def){return function(root,api){var html='<div class="hm-calc-panel"><div class="hm-calc-form">';if(def.hint)html+='<p class="hm-calc-hint">'+e(def.hint)+'</p>';html+='<div class="hm-calc-grid-2">'+def.fields.map(renderField).join('')+'</div><div class="hm-calc-actions"><button type="button" class="hm-calc-btn">계산하기</button></div><p class="hm-calc-message" hidden></p></div><div class="hm-calc-result" hidden></div></div>';root.innerHTML=html;var els=Array.prototype.slice.call(root.querySelectorAll('[data-key]')),go=root.querySelector('button'),msg=root.querySelector('.hm-calc-message'),res=root.querySelector('.hm-calc-result');go.addEventListener('click',function(){var x={};els.forEach(function(el){var k=el.getAttribute('data-key');if(el.tagName==='SELECT'||el.getAttribute('data-raw')==='1'||el.type==='date')x[k]=el.value;else x[k]=api.parseNumber(el.value);});var r=def.compute(x);if(r&&r.error){api.setMessage(msg,r.error);api.clearResult(res);return;}api.setMessage(msg,'');api.setResult(res,def.format(r,api));});};}
var defs=[{id:"body-fat-mass",fields:[{"key":"weightKg","label":"체중 (kg)","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"bodyFatPercent","label":"체지방률 (%)","type":"number","placeholder":"","default":"","options":[],"raw":false}],hint:"측정 기기와 방법에 따라 체지방률 오차가 있을 수 있습니다.",compute:function(x){var w=Number(x.weightKg),p=Number(x.bodyFatPercent);if(![w,p].every(Number.isFinite)||w<=0||p<0||p>100)return{error:"체중은 0보다 크게, 체지방률은 0~100%로 입력해 주세요."};var fat=w*p/100;return{fatMassKg:fat,leanMassKg:w-fat,fatPercent:p};},format:function(r,api){return api.resultCard("체지방량",api.formatNumber(r.fatMassKg,2)+"kg",api.formatNumber(r.fatPercent,1)+"%")+api.resultCard("제지방량",api.formatNumber(r.leanMassKg,2)+"kg","");}},{id:"macro-nutrient-grams",fields:[{"key":"calories","label":"하루 목표 열량 (kcal)","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"carbPercent","label":"탄수화물 비율 (%)","type":"number","placeholder":"","default":"50","options":[],"raw":false},{"key":"proteinPercent","label":"단백질 비율 (%)","type":"number","placeholder":"","default":"25","options":[],"raw":false},{"key":"fatPercent","label":"지방 비율 (%)","type":"number","placeholder":"","default":"25","options":[],"raw":false}],hint:"탄수화물과 단백질은 1g당 4kcal, 지방은 1g당 9kcal로 계산합니다.",compute:function(x){var c=Number(x.calories),a=Number(x.carbPercent),p=Number(x.proteinPercent),f=Number(x.fatPercent);if(![c,a,p,f].every(Number.isFinite)||c<0||a<0||p<0||f<0||Math.abs(a+p+f-100)>1e-9)return{error:"열량은 0 이상, 세 영양소 비율의 합은 100%가 되도록 입력해 주세요."};return{carbGrams:c*a/100/4,proteinGrams:c*p/100/4,fatGrams:c*f/100/9,totalPercent:a+p+f};},format:function(r,api){return api.resultCard("탄수화물",api.formatNumber(r.carbGrams,1)+"g","")+api.resultCard("단백질",api.formatNumber(r.proteinGrams,1)+"g","")+api.resultCard("지방",api.formatNumber(r.fatGrams,1)+"g","");}},{id:"swimming-pace",fields:[{"key":"distanceM","label":"수영 거리 (m)","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"minutes","label":"기록 분","type":"integer","placeholder":"","default":"0","options":[],"raw":false},{"key":"seconds","label":"기록 초","type":"number","placeholder":"","default":"0","options":[],"raw":false}],hint:"",compute:function(x){var d=Number(x.distanceM),m=Number(x.minutes),s=Number(x.seconds);if(![d,m,s].every(Number.isFinite)||d<=0||m<0||s<0||s>=60)return{error:"거리는 0보다 크게, 분은 0 이상, 초는 0~60 미만으로 입력해 주세요."};var total=m*60+s;if(total<=0)return{error:"기록 시간은 0보다 커야 합니다."};var pace=total/d*100;return{totalSeconds:total,pace100Seconds:pace,speedMps:d/total,speedKmh:d/total*3.6};},format:function(r,api){var pm=Math.floor(r.pace100Seconds/60),ps=r.pace100Seconds-pm*60;return api.resultCard("100m 페이스",pm+"분 "+api.formatNumber(ps,1)+"초","")+api.resultCard("평균 속도",api.formatNumber(r.speedKmh,2)+"km/h",api.formatNumber(r.speedMps,3)+"m/s");}},{id:"cycling-power-to-weight",fields:[{"key":"powerWatts","label":"평균 파워 (W)","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"weightKg","label":"현재 체중 (kg)","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"targetWeightKg","label":"비교 체중 (kg)","type":"number","placeholder":"","default":"","options":[],"raw":false}],hint:"",compute:function(x){var p=Number(x.powerWatts),w=Number(x.weightKg),t=Number(x.targetWeightKg);if(![p,w].every(Number.isFinite)||p<0||w<=0)return{error:"파워는 0 이상, 체중은 0보다 크게 입력해 주세요."};if(!Number.isFinite(t)||t<=0)t=w;return{currentWkg:p/w,targetWkg:p/t,difference:p/t-p/w};},format:function(r,api){return api.resultCard("현재 파워 대 체중비",api.formatNumber(r.currentWkg,3)+" W/kg","")+api.resultCard("비교 체중 기준",api.formatNumber(r.targetWkg,3)+" W/kg","차이 "+api.formatNumber(r.difference,3));}},{id:"cooper-vo2max",fields:[{"key":"distanceM","label":"12분 달린 거리 (m)","type":"number","placeholder":"","default":"","options":[],"raw":false}],hint:"쿠퍼 테스트 경험식에 따른 참고용 추정치이며 의료 진단용이 아닙니다.",compute:function(x){var d=Number(x.distanceM);if(!Number.isFinite(d)||d<=0)return{error:"12분 동안 달린 거리를 0보다 크게 입력해 주세요."};return{vo2max:(d-504.9)/44.73,distanceKm:d/1000};},format:function(r,api){return api.resultCard("VO₂max 추정값",api.formatNumber(r.vo2max,2)+" ml/kg/min","12분 거리 "+api.formatNumber(r.distanceKm,3)+"km");}},{id:"heart-rate-recovery",fields:[{"key":"peakHeartRate","label":"운동 직후 심박수 (bpm)","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"afterOneMinute","label":"1분 후 심박수 (bpm)","type":"number","placeholder":"","default":"","options":[],"raw":false}],hint:"운동 강도와 건강 상태에 따라 결과가 달라지며 의료 판단에는 사용하지 마세요.",compute:function(x){var p=Number(x.peakHeartRate),a=Number(x.afterOneMinute);if(![p,a].every(Number.isFinite)||p<=0||a<=0||a>p)return{error:"두 심박수는 0보다 크게, 1분 후 심박수는 운동 직후보다 크지 않게 입력해 주세요."};var drop=p-a;return{dropBpm:drop,recoveryPercent:drop/p*100,remainingPercent:a/p*100};},format:function(r,api){return api.resultCard("1분 회복 심박수",api.formatNumber(r.dropBpm,0)+" bpm 감소","")+api.resultCard("회복률",api.formatNumber(r.recoveryPercent,2)+"%","1분 후 비율 "+api.formatNumber(r.remainingPercent,2)+"%");}}];defs.forEach(function(def){w.HM_CALC.register(def.id,{compute:def.compute,render:makeRender(def)});});})(window);
